seed_files.stage1_ingest.py:
"""Stage 1: Ingest raw sensor data from CSV-like input."""

def parse_reading(line: str) -> dict:
    """Parse a sensor reading line: 'timestamp,sensor_id,value,unit'"""
    parts = line.strip().split(",")
    return {
        "timestamp": parts[0],
        "sensor_id": parts[1],
        "value": parts[2],  # BUG: should be float(parts[2])
        "unit": parts[3] if len(parts) > 3 else "unknown",
    }

def ingest_batch(lines: list) -> list:
    """Parse a batch of sensor readings."""
    readings = []
    for line in lines:
        if line.strip() and not line.startswith("#"):
            readings.append(parse_reading(line))
    return readings

def filter_valid(readings: list) -> list:
    """Filter out readings with missing or invalid data."""
    valid = []
    for r in readings:
        if r["sensor_id"] and r["value"] and r["timestamp"]:
            valid.append(r)
    return valid

seed_files.stage2_normalize.py:
"""Stage 2: Normalize sensor readings to standard units."""

CONVERSION_FACTORS = {
    ("fahrenheit", "celsius"): lambda v: (v - 32) * 5 / 9,
    ("celsius", "fahrenheit"): lambda v: v * 9 / 5 + 32,
    ("psi", "bar"): lambda v: v * 0.0689476,
    ("bar", "psi"): lambda v: v / 0.0689476,
    ("mph", "kph"): lambda v: v * 1.60934,
    ("kph", "mph"): lambda v: v / 1.60934,
}

STANDARD_UNITS = {
    "temperature": "celsius",
    "pressure": "bar",
    "speed": "kph",
}

UNIT_CATEGORIES = {
    "fahrenheit": "temperature",
    "celsius": "temperature",
    "psi": "pressure",
    "bar": "pressure",
    "mph": "speed",
    "kph": "speed",
}

def normalize_reading(reading: dict) -> dict:
    """Convert reading to standard units."""
    unit = reading["unit"].lower()
    category = UNIT_CATEGORIES.get(unit)

    if category is None:
        # Unknown unit, pass through
        return reading.copy()

    standard = STANDARD_UNITS[category]
    if unit == standard:
        return reading.copy()

    converter = CONVERSION_FACTORS.get((unit, standard))
    if converter is None:
        return reading.copy()

    result = reading.copy()
    result["value"] = converter(reading["value"])  # Will crash here because value is string, not float
    result["unit"] = standard
    result["original_unit"] = unit
    result["original_value"] = reading["value"]
    return result

def normalize_batch(readings: list) -> list:
    """Normalize a batch of readings. Skip failures."""
    normalized = []
    for r in readings:
        try:
            normalized.append(normalize_reading(r))
        except (TypeError, ValueError):
            # Silently skip conversion failures
            pass
    return normalized

seed_files.stage3_aggregate.py:
"""Stage 3: Aggregate normalized readings by sensor."""

from collections import defaultdict

def group_by_sensor(readings: list) -> dict:
    """Group readings by sensor_id."""
    groups = defaultdict(list)
    for r in readings:
        groups[r["sensor_id"]].append(r)
    return dict(groups)

def compute_stats(readings: list) -> dict:
    """Compute min/max/avg for a list of readings."""
    if not readings:
        return {"min": 0, "max": 0, "avg": 0, "count": 0}

    values = [r["value"] for r in readings]
    return {
        "min": min(values),
        "max": max(values),
        "avg": sum(values) / len(values),
        "count": len(values),
    }

def aggregate(readings: list) -> dict:
    """Aggregate readings into per-sensor statistics."""
    groups = group_by_sensor(readings)
    result = {}
    for sensor_id, sensor_readings in groups.items():
        result[sensor_id] = compute_stats(sensor_readings)
    return result
